def rotate_matrix_90(matrix):
    n = len(matrix)
    rotated = [[0] * n for _ in range(n)]

    for i in range(n):
        for j in range(n):
            rotated[j][n - 1 - i] = matrix[i][j]

    return rotated


def print_matrix(matrix):
    for row in matrix:
        print(row)
